import React from 'react';
import { ProductList } from './ProductList';
import './styles.css';

const initialProducts = [
  { id: 1, name: 'Wireless Mouse', price: 29.99, category: 'Electronics' },
  { id: 2, name: 'Mechanical Keyboard', price: 89.99, category: 'Electronics' },
  { id: 3, name: 'USB-C Hub', price: 39.99, category: 'Electronics' },
  { id: 4, name: 'Desk Lamp', price: 24.99, category: 'Office' },
  { id: 5, name: 'Notebook Pack', price: 12.99, category: 'Office' },
  { id: 6, name: 'Coffee Mug', price: 14.99, category: 'Kitchen' },
  { id: 7, name: 'Water Bottle', price: 19.99, category: 'Kitchen' },
  { id: 8, name: 'Standing Mat', price: 49.99, category: 'Office' },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Product Catalog</h1>
      <ProductList products={initialProducts} />
    </div>
  );
}

import React, { useState, useRef, useCallback } from 'react';
import './styles.css';

interface Product {
  id: number;
  name: string;
  price: number;
  category: string;
}

interface ProductItemProps {
  product: Product;
  isFavorite: boolean;
  onToggle: (id: number) => void;
}

// TODO: Wrap with React.memo to prevent unnecessary re-renders
const ProductItem: React.FC<ProductItemProps> = ({ product, isFavorite, onToggle }) => {
  const renderCount = useRef(0);
  renderCount.current++;

  return (
    <div data-testid={`product-${product.id}`} className="product">
      <div className="product__info">
        <span className="product__name">{product.name}</span>
        <span className="product__price">${product.price}</span>
      </div>
      <div className="product__actions">
        <button
          data-testid={`fav-${product.id}`}
          className={`product__fav${isFavorite ? ' product__fav--active' : ''}`}
          onClick={() => onToggle(product.id)}
        >
          {isFavorite ? '★' : '☆'}
        </button>
        <span data-testid={`render-count-${product.id}`} className="product__renders">
          renders: {renderCount.current}
        </span>
      </div>
    </div>
  );
};

interface ProductListProps {
  products: Product[];
}

export const ProductList: React.FC<ProductListProps> = ({ products }) => {
  const [search, setSearch] = useState('');
  const [favorites, setFavorites] = useState<Set<number>>(new Set());
  const totalRenders = useRef(0);

  // BUG: This creates a new function on every render, causing all items to re-render
  const toggleFavorite = (id: number) => {
    setFavorites(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const filtered = products.filter(p =>
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  // Count total renders across all visible items
  totalRenders.current++;

  return (
    <div>
      <input
        data-testid="search"
        className="search-input"
        placeholder="Search products…"
        value={search}
        onChange={e => setSearch(e.target.value)}
      />
      <p data-testid="total-renders" className="total-renders">
        List renders: {totalRenders.current}
      </p>
      <div className="product-list">
        {filtered.map(product => (
          <ProductItem
            key={product.id}
            product={product}
            isFavorite={favorites.has(product.id)}
            onToggle={toggleFavorite}
          />
        ))}
      </div>
    </div>
  );
};

.search-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  margin-bottom: 0.75rem;
}

.search-input:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 1px;
}

.total-renders {
  font-size: 0.75rem;
  color: #9ca3af;
  margin-bottom: 0.5rem;
}

.product-list {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.product {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.75rem 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
  background: white;
}

.product__info {
  display: flex;
  flex-direction: column;
  gap: 0.125rem;
}

.product__name {
  font-weight: 500;
  font-size: 0.875rem;
  color: #111827;
}

.product__price {
  font-size: 0.8125rem;
  color: #6b7280;
}

.product__actions {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.product__fav {
  background: none;
  border: none;
  font-size: 1.25rem;
  cursor: pointer;
  color: #d1d5db;
}

.product__fav--active {
  color: #f59e0b;
}

.product__renders {
  font-size: 0.6875rem;
  color: #d1d5db;
}

