import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Memoized List Rendering', () => {
  it('renders all products initially', () => {
    render(<App />);
    expect(screen.getByTestId('product-1')).toBeInTheDocument();
    expect(screen.getByTestId('product-8')).toBeInTheDocument();
  });

  it('filters products by search', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('search'), { target: { value: 'mouse' } });
    expect(screen.getByTestId('product-1')).toBeInTheDocument();
    expect(screen.queryByTestId('product-2')).not.toBeInTheDocument();
  });

  it('toggling favorite updates the button', () => {
    render(<App />);
    const fav = screen.getByTestId('fav-1');
    expect(fav).toHaveTextContent('☆');
    fireEvent.click(fav);
    expect(fav).toHaveTextContent('★');
  });

  it('render count is displayed for each item', () => {
    render(<App />);
    expect(screen.getByTestId('render-count-1')).toBeInTheDocument();
  });

  it('non-toggled items do not re-render on favorite toggle', () => {
    render(<App />);
    const count2Before = screen.getByTestId('render-count-2').textContent;
    fireEvent.click(screen.getByTestId('fav-1'));
    const count2After = screen.getByTestId('render-count-2').textContent;
    expect(count2After).toBe(count2Before);
  });

  it('total renders counter is displayed', () => {
    render(<App />);
    expect(screen.getByTestId('total-renders')).toBeInTheDocument();
  });
});

